    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int32_t *kernel_h = attrs->GetAttrPointer<int32_t>(0);
    const int32_t *kernel_w = attrs->GetAttrPointer<int32_t>(1);
    const int32_t *stride_h = attrs->GetAttrPointer<int32_t>(2);
    const int32_t *stride_w = attrs->GetAttrPointer<int32_t>(3);
